function renderPlatformHealthView() {
  var health = SA.data.system_health || {};
  var paywall = SA.data.paywall_status || {};

  var db = health.database || {};
  var act = health.activity || {};
  var errs = health.errors || {};
  var subs = health.subscriptions || {};
  var tel = health.telephony || {};
  var integrations = health.integrations || [];
  var generated = health.generated_at ? new Date(health.generated_at) : null;
  var ageSec = generated ? Math.max(0, Math.round((Date.now() - generated.getTime()) / 1000)) : null;

  // ── At-a-Glance KPIs ──
  var mrrDollars = centsToD(subs.mrr_cents || paywall.mrr_cents || 0);
  var activeSubs = (subs.active != null ? subs.active : (paywall.active_subs || 0));
  var trialSubs = (subs.trial != null ? subs.trial : (paywall.trial_subs || 0));
  var totalErrors = (errs.failed_orders_7d || 0) + (errs.unprocessed_webhooks_7d || 0);
  var errColor = totalErrors === 0 ? 'green' : totalErrors < 5 ? 'amber' : 'red';

  var kpisHtml = '<div class="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-4">' +
    samc('MRR', mrrDollars, 'fa-dollar-sign', 'green', 'ARR ' + centsToD((subs.arr_cents || (subs.mrr_cents||0)*12))) +
    samc('Active Subs', activeSubs, 'fa-users-cog', 'indigo', (subs.past_due || 0) + ' past due') +
    samc('Trial Users', trialSubs, 'fa-gift', 'purple') +
    samc('Orders 24h', act.orders_24h || 0, 'fa-shopping-cart', 'blue', (act.orders_7d || 0) + ' (7d)') +
    samc('Signups 24h', act.signups_24h || 0, 'fa-user-plus', 'teal', (act.signups_7d || 0) + ' (7d)') +
    samc('Errors 7d', totalErrors, 'fa-exclamation-triangle', errColor) +
  '</div>';

  // ── System Status ──
  var dbColor = db.status === 'ok' ? 'green' : 'red';
  var dbLatencyLabel = db.latency_ms != null ? (db.latency_ms + ' ms') : '—';
  var refreshedLabel = ageSec == null ? '—' : (ageSec < 60 ? ageSec + 's ago' : Math.round(ageSec/60) + 'm ago');
  var statusHtml = '<div class="grid grid-cols-1 md:grid-cols-3 gap-4">' +
    samc('Database', db.status === 'ok' ? 'Connected' : 'Error', 'fa-database', dbColor, dbLatencyLabel + ' · ' + (db.customers || 0) + ' customers') +
    samc('Edge Runtime', 'Cloudflare Workers', 'fa-cloud', 'green', 'Globally distributed') +
    samc('Last Refreshed', refreshedLabel, 'fa-sync', 'gray', generated ? generated.toLocaleTimeString() : '') +
  '</div>';

  // ── Integration Health ──
  var integrationsHtml = '';
  if (!integrations.length) {
    integrationsHtml = '<p class="text-sm text-slate-400 italic">No integration data available.</p>';
  } else {
    integrationsHtml = '<div class="space-y-2">';
    integrations.forEach(function(group) {
      var keys = group.keys || [];
      var present = keys.filter(function(k){ return k.present; }).length;
      var total = keys.length;
      var groupColor = present === total ? 'green' : present === 0 ? 'red' : 'amber';
      var keyPills = keys.map(function(k){
        var c = k.present ? 'bg-green-50 text-green-700 border-green-200' : 'bg-red-50 text-red-700 border-red-200';
        var icon = k.present ? 'fa-check' : 'fa-times';
        return '<span class="inline-flex items-center gap-1 px-2 py-0.5 text-[11px] font-medium rounded border ' + c + '"><i class="fas ' + icon + ' text-[9px]"></i>' + k.key + '</span>';
      }).join('');
      integrationsHtml +=
        '<div class="flex items-start gap-3 p-3 rounded-lg border border-slate-100 bg-white">' +
          '<div class="w-9 h-9 bg-' + groupColor + '-50 rounded-lg flex items-center justify-center flex-shrink-0"><i class="fas ' + (group.icon || 'fa-cog') + ' text-' + groupColor + '-500"></i></div>' +
          '<div class="flex-1 min-w-0">' +
            '<div class="flex items-center justify-between mb-1.5">' +
              '<span class="font-semibold text-sm text-slate-700">' + group.name + '</span>' +
              '<span class="text-[11px] font-semibold text-' + groupColor + '-600">' + present + '/' + total + '</span>' +
            '</div>' +
            '<div class="flex flex-wrap gap-1">' + keyPills + '</div>' +
          '</div>' +
        '</div>';
    });
    integrationsHtml += '</div>';
  }

  // ── Activity ──
  var activityHtml = '<div class="grid grid-cols-2 md:grid-cols-4 gap-4">' +
    samc('Orders', act.orders_24h || 0, 'fa-clipboard-list', 'blue', (act.orders_7d||0) + ' (7d) · ' + (act.orders_30d||0) + ' (30d)') +
    samc('Signups', act.signups_24h || 0, 'fa-user-plus', 'teal', (act.signups_7d||0) + ' (7d) · ' + (act.signups_30d||0) + ' (30d)') +
    samc('Leads', act.leads_24h || 0, 'fa-bullseye', 'amber', (act.leads_7d||0) + ' (7d)') +
    samc('Reports', act.reports_24h || 0, 'fa-file-alt', 'indigo', (act.reports_7d||0) + ' (7d)') +
  '</div>';

  // ── Error Watch ──
  var failColor = (errs.failed_orders_7d || 0) === 0 ? 'green' : (errs.failed_orders_7d || 0) < 3 ? 'amber' : 'red';
  var hookColor = (errs.unprocessed_webhooks_7d || 0) === 0 ? 'green' : (errs.unprocessed_webhooks_7d || 0) < 5 ? 'amber' : 'red';
  var errorHtml = '<div class="grid grid-cols-1 md:grid-cols-2 gap-4">' +
    samc('Failed Orders (7d)', errs.failed_orders_7d || 0, 'fa-times-circle', failColor, (errs.failed_orders_7d || 0) === 0 ? 'All clear' : 'Investigate in Orders tab') +
    samc('Unprocessed Webhooks (7d)', errs.unprocessed_webhooks_7d || 0, 'fa-bolt', hookColor, (errs.unprocessed_webhooks_7d || 0) === 0 ? 'All processed' : 'Square / Stripe events pending') +
  '</div>';

  // ── Paywall & Subscriptions ──
  var paywallEnabled = !!paywall.enabled;
  var paywallColor = paywallEnabled ? 'green' : 'gray';
  var paywallHtml = '<div class="grid grid-cols-2 md:grid-cols-4 gap-4">' +
    samc('Paywall', paywallEnabled ? 'Enabled' : 'Disabled', 'fa-lock', paywallColor, paywallEnabled ? 'Gating features for free users' : 'Free access · set settings.paywall_enabled=true to enable') +
    samc('Trial Days', paywall.trial_days || 7, 'fa-calendar', 'blue', 'settings.paywall_trial_days') +
    samc('MRR', centsToD(paywall.mrr_cents || 0), 'fa-dollar-sign', 'green') +
    samc('Paying Customers (12m)', paywall.paying_count || 0, 'fa-credit-card', 'amber') +
  '</div>';

  // Tiers + packages tables (preserved from previous endpoint shape)
  var tiers = paywall.tiers || [];
  var packages = paywall.packages || [];
  if (tiers.length || packages.length) {
    paywallHtml += '<div class="grid grid-cols-1 md:grid-cols-2 gap-4 mt-4">';
    if (tiers.length) {
      var tierRows = tiers.map(function(t){
        var label = t.subscription_plan || '—';
        return '<tr class="border-t border-slate-100"><td class="py-1.5 text-sm text-slate-700">' + label + '</td><td class="py-1.5 text-sm text-right font-semibold">' + (t.cnt || 0) + '</td></tr>';
      }).join('');
      paywallHtml += '<div class="bg-white rounded-xl border border-slate-100 p-4">' +
        '<div class="text-xs font-semibold text-slate-400 uppercase tracking-wider mb-2">Active Customers by Plan</div>' +
        '<table class="w-full"><tbody>' + tierRows + '</tbody></table>' +
      '</div>';
    }
    if (packages.length) {
      var pkgRows = packages.map(function(p){
        var price = p.price_cents != null ? centsToD(p.price_cents) : (p.price ? '$' + p.price : '—');
        return '<tr class="border-t border-slate-100"><td class="py-1.5 text-sm text-slate-700">' + (p.name || '—') + '</td><td class="py-1.5 text-sm text-right">' + (p.credits || 0) + ' cr</td><td class="py-1.5 text-sm text-right font-semibold">' + price + '</td></tr>';
      }).join('');
      paywallHtml += '<div class="bg-white rounded-xl border border-slate-100 p-4">' +
        '<div class="text-xs font-semibold text-slate-400 uppercase tracking-wider mb-2">Active Credit Packages</div>' +
        '<table class="w-full"><tbody>' + pkgRows + '</tbody></table>' +
      '</div>';
    }
    paywallHtml += '</div>';
  }

  // ── Telephony Health ──
  var phonesAssignedPct = tel.phones_total ? Math.round(((tel.phones_assigned||0) / tel.phones_total) * 100) : 0;
  var agentsConnPct = tel.agents_total ? Math.round(((tel.agents_connected||0) / tel.agents_total) * 100) : 0;
  var phoneColor = (tel.phones_total||0) === 0 ? 'gray' : phonesAssignedPct < 80 ? 'green' : 'amber';
  var agentColor = (tel.agents_total||0) === 0 ? 'gray' : agentsConnPct >= 90 ? 'green' : agentsConnPct >= 50 ? 'amber' : 'red';
  var telephonyHtml = '<div class="grid grid-cols-2 md:grid-cols-4 gap-4">' +
    samc('Phone Pool', (tel.phones_assigned||0) + ' / ' + (tel.phones_total||0), 'fa-phone', phoneColor, (tel.phones_available||0) + ' available') +
    samc('Pool Utilization', phonesAssignedPct + '%', 'fa-percentage', phoneColor) +
    samc('Active Agents', (tel.agents_connected||0) + ' / ' + (tel.agents_total||0), 'fa-headset', agentColor, agentsConnPct + '% connected') +
    samc('Agents Total', tel.agents_total || 0, 'fa-robot', 'indigo') +
  '</div>';

  return '<div class="mb-5"><h2 class="text-2xl font-black text-gray-900"><i class="fas fa-heartbeat mr-2 text-red-500"></i>System Health</h2>' +
      '<p class="text-sm text-gray-500 mt-1">Real-time platform telemetry · refreshed ' + refreshedLabel + '</p></div>' +
    '<div class="space-y-6">' +
      saSection('At a Glance', 'fa-tachometer-alt', kpisHtml) +
      saSection('System Status', 'fa-server', statusHtml) +
      saSection('Integration Health', 'fa-plug', integrationsHtml) +
      saSection('Activity', 'fa-bolt', activityHtml) +
      saSection('Error Watch', 'fa-exclamation-triangle', errorHtml) +
      saSection('Paywall & Subscriptions', 'fa-lock', paywallHtml) +
      saSection('Telephony Health', 'fa-phone-volume', telephonyHtml) +
    '</div>';
}

// ============================================================
// PLATFORM — HEALTH CHECK LOG (monitor agent run history + insights)
// ============================================================
// Friendly labels for monitor error_codes — keeps raw 4xx JSON out of the UI.
var HCL_ERROR_LABELS = {
  insufficient_credits: 'Insufficient Anthropic credits',
  auth_failed: 'Anthropic auth failed',
  rate_limited: 'Anthropic rate-limited',
  model_unavailable: 'Anthropic model unavailable',
  timeout: 'Anthropic timed out',
  network: 'Network error reaching Anthropic',
  parse_error: 'Could not parse Claude response',
  missing_api_key: 'ANTHROPIC_API_KEY missing',
  circuit_open: 'Skipped — circuit breaker',
  unknown: 'Unknown error'
};

function hclLabelForRun(r) {
  // Prefer structured error_code; fall back to a cleaned-up summary.
  var code = r && r.details && r.details.error_code;
  if (code && HCL_ERROR_LABELS[code]) return HCL_ERROR_LABELS[code];
  if (r && r.details && r.details.error_label) return r.details.error_label;
  var s = (r && r.summary) || '';
  // Strip raw 400 JSON dumps so they never reach the user
  if (/credit balance is too low/i.test(s)) return HCL_ERROR_LABELS.insufficient_credits;
  if (/^4\d\d\s*\{/.test(s)) return 'Anthropic API error';
  return s || '—';
}

function renderHealthCheckLogView() {
  var d = SA.data.health_check_log || {};
  var cfg = d.config || {};
  var runs = d.runs || [];
  var rollup = d.rollup || {};
  var insights = d.insights || [];
  var ic = d.insight_counts || {};
  var memory = d.memory || [];
  var diag = d.diagnostic || {};

  var lastRun = runs[0] || null;
  // Ignore empty {} details_json — it confuses the empty-state check
  var lastDetails = (lastRun && lastRun.details && Object.keys(lastRun.details).length > 0) ? lastRun.details : null;
  var lastSuccess = null;
  for (var i = 0; i < runs.length; i++) { if (runs[i].status === 'success') { lastSuccess = runs[i]; break; } }
  var generated = d.generated_at ? new Date(d.generated_at) : null;
  var refreshedLabel = generated ? generated.toLocaleTimeString() : '—';

  // ── Diagnostic banner ──────────────────────────────────────
  var bannerHtml = '';
  var an = diag.action_needed;
  if (an) {
    var bannerCss = an.severity === 'critical'
      ? 'bg-red-50 border-red-200 text-red-800'
      : an.severity === 'warning'
      ? 'bg-amber-50 border-amber-200 text-amber-800'
      : 'bg-blue-50 border-blue-200 text-blue-800';
    var bannerIcon = an.severity === 'critical' ? 'fa-circle-exclamation' : an.severity === 'warning' ? 'fa-triangle-exclamation' : 'fa-circle-info';
    var ctaHtml = (an.cta_url && an.cta_label)
      ? '<a href="' + escapeHtml(an.cta_url) + '" target="_blank" rel="noopener" class="inline-flex items-center gap-1.5 px-3 py-1.5 bg-white border border-current rounded-lg text-xs font-semibold hover:bg-opacity-80"><i class="fas fa-arrow-up-right-from-square text-[10px]"></i>' + escapeHtml(an.cta_label) + '</a>'
      : '';
    bannerHtml =
      '<div class="rounded-xl border ' + bannerCss + ' p-4 flex items-start gap-3 mb-4">' +
        '<i class="fas ' + bannerIcon + ' text-lg mt-0.5"></i>' +
        '<div class="flex-1 min-w-0">' +
          '<p class="font-bold text-sm">' + escapeHtml(an.title) + '</p>' +
          '<p class="text-xs mt-1 opacity-90 leading-relaxed">' + escapeHtml(an.message) + '</p>' +
        '</div>' +
        (ctaHtml ? '<div class="flex-shrink-0">' + ctaHtml + '</div>' : '') +
      '</div>';
  }

  // ── Header KPIs ─────────────────────────────────────────────
  var enabledLabel = cfg.enabled ? 'Enabled' : 'Disabled';
  var enabledColor = cfg.enabled ? 'green' : 'gray';
  var lastStatus = cfg.last_run_status || (lastRun ? lastRun.status : '—');
  var statusColor = lastStatus === 'success' ? 'green' : lastStatus === 'error' ? 'red' : lastStatus === 'skipped' ? 'gray' : 'amber';
  var lastRunAt = cfg.last_run_at || (lastRun ? lastRun.created_at : null);
  var lastRunLabel = lastRunAt ? fmtDateTime(lastRunAt) : 'Never';
  var errColor = (rollup.errors_24h || 0) === 0 ? 'green' : (rollup.errors_24h || 0) < 2 ? 'amber' : 'red';
  var critColor = (ic.critical_open || 0) === 0 ? 'green' : 'red';

  var kpisHtml = '<div class="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-4">' +
    samc('Monitor Agent', enabledLabel, 'fa-power-off', enabledColor, 'hourly @ :00') +
    samc('Last Run', lastStatus, 'fa-history', statusColor, lastRunLabel) +
    samc('Runs (7d)', rollup.runs_7d || 0, 'fa-redo', 'indigo', (rollup.runs_24h || 0) + ' (24h)') +
    samc('Errors (7d)', rollup.errors_7d || 0, 'fa-exclamation-triangle', errColor, (rollup.errors_24h || 0) + ' (24h)') +
    samc('Open Insights', ic.open || 0, 'fa-lightbulb', 'amber', (ic.acknowledged || 0) + ' ack · ' + (ic.resolved || 0) + ' resolved') +
    samc('Critical Open', ic.critical_open || 0, 'fa-skull-crossbones', critColor, (ic.high_open || 0) + ' high') +
  '</div>';

  // ── Hero "Latest Run" card with sparkline ────────────────────
  var heroHtml;
  var hs = lastSuccess && lastSuccess.details ? lastSuccess.details.health_score : null;
  if (hs == null) {
    heroHtml =
      '<div class="rounded-2xl bg-gradient-to-br from-slate-50 to-white border border-slate-200 p-6">' +
        '<div class="flex items-start gap-4">' +
          '<div class="w-14 h-14 bg-slate-100 rounded-xl flex items-center justify-center"><i class="fas fa-heart-pulse text-slate-400 text-xl"></i></div>' +
          '<div class="flex-1">' +
            '<p class="text-[11px] font-semibold text-slate-400 uppercase tracking-wider">Latest Successful Scan</p>' +
            '<p class="text-2xl font-extrabold text-slate-700 mt-1">Waiting on first successful run</p>' +
            '<p class="text-xs text-slate-500 mt-2 leading-relaxed">Once the monitor agent completes a scan, this card will show the health score, trend, and a sparkline of the last 30 runs. Use "Run scan now" to trigger one immediately.</p>' +
          '</div>' +
        '</div>' +
      '</div>';
  } else {
    var hsColor = hs >= 80 ? 'green' : hs >= 60 ? 'amber' : 'red';
    var hsBg = hs >= 80 ? 'from-green-50 to-emerald-50 border-green-100' : hs >= 60 ? 'from-amber-50 to-yellow-50 border-amber-100' : 'from-red-50 to-rose-50 border-red-100';
    // Sparkline of last 30 health scores from successful runs (oldest → newest)
    var sparkPoints = runs.slice().reverse()
      .filter(function(r){ return r.status === 'success' && r.details && r.details.health_score != null; })
      .map(function(r){ return r.details.health_score; });
    var spark = '';
    if (sparkPoints.length >= 2) {
      var w = 240, h = 50, n = sparkPoints.length;
      var maxV = 100, minV = 0;
      var pts = sparkPoints.map(function(v, idx){
        var x = (idx / (n - 1)) * w;
        var y = h - ((v - minV) / (maxV - minV)) * h;
        return x.toFixed(1) + ',' + y.toFixed(1);
      }).join(' ');
      var areaPts = '0,' + h + ' ' + pts + ' ' + w + ',' + h;
      var strokeColor = hsColor === 'green' ? '#10b981' : hsColor === 'amber' ? '#f59e0b' : '#ef4444';
      spark =
        '<svg viewBox="0 0 ' + w + ' ' + h + '" class="w-full h-12">' +
          '<polygon points="' + areaPts + '" fill="' + strokeColor + '" opacity="0.12"/>' +
          '<polyline points="' + pts + '" fill="none" stroke="' + strokeColor + '" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>' +
        '</svg>';
    } else {
      spark = '<p class="text-[10px] text-slate-400 italic">Sparkline appears after 2+ successful runs</p>';
    }
    var iss = lastSuccess.details.issues_found || 0;
    var crit = lastSuccess.details.critical_count || 0;
    heroHtml =
      '<div class="rounded-2xl bg-gradient-to-br ' + hsBg + ' border p-6">' +
        '<div class="grid grid-cols-1 md:grid-cols-3 gap-6">' +
          '<div>' +
            '<p class="text-[11px] font-semibold text-slate-500 uppercase tracking-wider">Health Score</p>' +
            '<p class="text-5xl font-black text-' + hsColor + '-600 mt-1 leading-none">' + hs + '<span class="text-2xl text-' + hsColor + '-400">/100</span></p>' +
            '<p class="text-xs text-slate-500 mt-2">' + fmtDateTime(lastSuccess.created_at) + '</p>' +
          '</div>' +
          '<div>' +
            '<p class="text-[11px] font-semibold text-slate-500 uppercase tracking-wider">Findings</p>' +
            '<p class="text-3xl font-extrabold text-slate-700 mt-1">' + iss + '</p>' +
            '<p class="text-xs text-slate-500 mt-2">' + (crit > 0 ? '<span class="text-red-600 font-semibold">' + crit + ' critical</span>' : 'No critical issues') + '</p>' +
          '</div>' +
          '<div>' +
            '<p class="text-[11px] font-semibold text-slate-500 uppercase tracking-wider">Health trend (last 30 runs)</p>' +
            '<div class="mt-1">' + spark + '</div>' +
          '</div>' +
        '</div>' +
      '</div>';
  }

  // ── Recent Runs (collapses contiguous repeat errors) ─────────
  var runsHtml;
  if (!runs.length) {
    runsHtml = '<p class="text-sm text-slate-300 italic">No monitor runs recorded yet.</p>';
  } else {
    // Group head streak of identical error labels into a single collapsed row
    var headLabel = hclLabelForRun(runs[0]);
    var streakLen = 0;
    if (runs[0].status !== 'success') {
      for (var k = 0; k < runs.length; k++) {
        if (runs[k].status === 'success') break;
        if (hclLabelForRun(runs[k]) !== headLabel) break;
        streakLen++;
      }
    }
    var collapsed = streakLen >= 3;
    var visibleRuns = collapsed ? runs.slice(streakLen) : runs;
    var firstStreak = collapsed ? runs[streakLen - 1] : null;
    var lastStreak = collapsed ? runs[0] : null;

    var runRows = visibleRuns.map(function(r){
      var sColor = r.status === 'success' ? 'green' : r.status === 'error' ? 'red' : r.status === 'skipped' ? 'gray' : 'amber';
      var sIcon = r.status === 'success' ? 'fa-check-circle' : r.status === 'error' ? 'fa-times-circle' : r.status === 'skipped' ? 'fa-forward' : 'fa-circle-exclamation';
      var hsCell = (r.details && r.details.health_score != null) ? (r.details.health_score + '/100') : '—';
      var issCell = (r.details && r.details.issues_found != null) ? r.details.issues_found : '—';
      var label = r.status === 'success' ? (r.summary || hclLabelForRun(r)) : hclLabelForRun(r);
      return '<tr class="border-t border-slate-100 hover:bg-slate-50">' +
        '<td class="py-2 px-3 text-xs text-slate-500 whitespace-nowrap">' + fmtDateTime(r.created_at) + '</td>' +
        '<td class="py-2 px-3"><span class="inline-flex items-center gap-1.5 px-2 py-0.5 bg-' + sColor + '-50 text-' + sColor + '-700 rounded-full text-[11px] font-semibold capitalize"><i class="fas ' + sIcon + ' text-[9px]"></i>' + (r.status || '—') + '</span></td>' +
        '<td class="py-2 px-3 text-sm text-slate-700">' + escapeHtml(label) + '</td>' +
        '<td class="py-2 px-3 text-xs text-right text-slate-600">' + hsCell + '</td>' +
        '<td class="py-2 px-3 text-xs text-right text-slate-600">' + issCell + '</td>' +
        '<td class="py-2 px-3 text-xs text-right text-slate-500 whitespace-nowrap">' + (r.duration_ms != null ? r.duration_ms + ' ms' : '—') + '</td>' +
      '</tr>';
    }).join('');
    var collapsedRow = '';
    if (collapsed) {
      collapsedRow =
        '<tr class="bg-amber-50/60 border-t border-amber-100">' +
          '<td colspan="6" class="py-3 px-3">' +
            '<div class="flex items-center gap-3">' +
              '<i class="fas fa-layer-group text-amber-500"></i>' +
              '<div class="flex-1">' +
                '<p class="text-sm font-semibold text-amber-800">' + streakLen + ' consecutive runs failed with "' + escapeHtml(headLabel) + '"</p>' +
                '<p class="text-[11px] text-amber-700/80 mt-0.5">From ' + fmtDateTime(firstStreak.created_at) + ' to ' + fmtDateTime(lastStreak.created_at) + '</p>' +
              '</div>' +
            '</div>' +
          '</td>' +
        '</tr>';
    }
    runsHtml = '<div class="overflow-x-auto"><table class="w-full">' +
      '<thead><tr class="bg-slate-50">' +
        '<th class="py-2 px-3 text-left text-[11px] font-semibold text-slate-500 uppercase tracking-wider">When</th>' +
        '<th class="py-2 px-3 text-left text-[11px] font-semibold text-slate-500 uppercase tracking-wider">Status</th>' +
        '<th class="py-2 px-3 text-left text-[11px] font-semibold text-slate-500 uppercase tracking-wider">Summary</th>' +
        '<th class="py-2 px-3 text-right text-[11px] font-semibold text-slate-500 uppercase tracking-wider">Health</th>' +
        '<th class="py-2 px-3 text-right text-[11px] font-semibold text-slate-500 uppercase tracking-wider">Issues</th>' +
        '<th class="py-2 px-3 text-right text-[11px] font-semibold text-slate-500 uppercase tracking-wider">Duration</th>' +
      '</tr></thead><tbody>' + collapsedRow + runRows + '</tbody></table></div>';
  }

  // ── Insights ────────────────────────────────────────────────
  var insightsHtml;
  if (!insights.length) {
    insightsHtml = '<p class="text-sm text-slate-300 italic">No insights yet — the monitor generates these from each successful scan.</p>';
  } else {
    var insightRows = insights.map(function(ins){
      var sevColor = ins.severity === 'critical' ? 'red' : ins.severity === 'high' ? 'amber' : ins.severity === 'medium' ? 'yellow' : 'blue';
      var catIcon = ins.category === 'bug' ? 'fa-bug' : ins.category === 'error' ? 'fa-exclamation-triangle' : ins.category === 'improvement' ? 'fa-lightbulb' : ins.category === 'performance' ? 'fa-tachometer-alt' : 'fa-heartbeat';
      var statColor = ins.status === 'open' ? 'amber' : ins.status === 'acknowledged' ? 'blue' : 'green';
      var actions = '';
      if (ins.status === 'open') {
        actions = '<button onclick="hclAckInsight(' + ins.id + ')" class="text-[10px] font-semibold text-blue-600 hover:text-blue-800 px-2 py-0.5 rounded hover:bg-blue-50">Acknowledge</button>' +
                  '<button onclick="hclResolveInsight(' + ins.id + ')" class="text-[10px] font-semibold text-green-600 hover:text-green-800 px-2 py-0.5 rounded hover:bg-green-50">Resolve</button>';
      } else if (ins.status === 'acknowledged') {
        actions = '<button onclick="hclResolveInsight(' + ins.id + ')" class="text-[10px] font-semibold text-green-600 hover:text-green-800 px-2 py-0.5 rounded hover:bg-green-50">Resolve</button>';
      }
      return '<div class="rounded-lg border border-slate-100 bg-white border-l-4 border-l-' + sevColor + '-400">' +
        '<div class="p-3 flex items-start gap-3">' +
          '<div class="w-9 h-9 bg-' + sevColor + '-50 rounded-lg flex items-center justify-center flex-shrink-0"><i class="fas ' + catIcon + ' text-' + sevColor + '-500"></i></div>' +
          '<div class="flex-1 min-w-0">' +
            '<div class="flex flex-wrap items-center gap-2 mb-1">' +
              '<span class="font-semibold text-sm text-slate-800">' + escapeHtml(ins.title || '—') + '</span>' +
              '<span class="inline-flex items-center px-1.5 py-0.5 bg-' + sevColor + '-100 text-' + sevColor + '-700 rounded text-[10px] font-bold uppercase">' + (ins.severity || '—') + '</span>' +
              '<span class="inline-flex items-center px-1.5 py-0.5 bg-slate-100 text-slate-600 rounded text-[10px] font-medium uppercase">' + (ins.category || '—') + '</span>' +
              '<span class="inline-flex items-center px-1.5 py-0.5 bg-' + statColor + '-50 text-' + statColor + '-700 rounded text-[10px] font-medium capitalize">' + (ins.status || 'open') + '</span>' +
              '<span class="text-[10px] text-slate-400 ml-auto">' + fmtDateTime(ins.created_at) + '</span>' +
            '</div>' +
            (ins.description ? '<p class="text-xs text-slate-600 mb-1.5">' + escapeHtml(ins.description) + '</p>' : '') +
            (ins.suggested_fix ? '<p class="text-xs text-slate-500"><span class="font-semibold text-slate-600">Suggested fix:</span> ' + escapeHtml(ins.suggested_fix) + '</p>' : '') +
            (actions ? '<div class="flex items-center gap-1 mt-2">' + actions + '</div>' : '') +
          '</div>' +
        '</div>' +
      '</div>';
    }).join('');
    insightsHtml = '<div class="space-y-2">' + insightRows + '</div>';
  }

  // ── Memory ──────────────────────────────────────────────────
  var memoryHtml;
  if (!memory.length) {
    memoryHtml = '<p class="text-sm text-slate-300 italic">No accumulated memory yet — builds up as the monitor learns the platform across successful scans.</p>';
  } else {
    memoryHtml = '<div class="space-y-3">' + memory.map(function(m){
      return '<div class="p-3 rounded-lg border border-slate-100 bg-slate-50">' +
        '<div class="flex items-center justify-between mb-1.5">' +
          '<span class="font-semibold text-xs text-slate-600 uppercase tracking-wider">' + escapeHtml(m.memory_key || '—') + '</span>' +
          '<span class="text-[10px] text-slate-400">updated ' + fmtDateTime(m.updated_at) + '</span>' +
        '</div>' +
        '<p class="text-xs text-slate-700 whitespace-pre-wrap leading-relaxed">' + escapeHtml(m.memory_value || '') + '</p>' +
      '</div>';
    }).join('') + '</div>';
  }

  // ── Action button: Run scan now ─────────────────────────────
  var actionsHtml =
    '<button id="hcl-run-now-btn" onclick="hclRunNow()" class="inline-flex items-center gap-2 px-3 py-1.5 bg-blue-600 hover:bg-blue-700 text-white rounded-lg text-xs font-semibold shadow-sm">' +
      '<i class="fas fa-play text-[10px]"></i><span>Run scan now</span>' +
    '</button>';

  // ── Help tooltip helper (inline, hover-revealed) ────────────
  function help(text) {
    return '<span class="relative group inline-flex items-center ml-1.5"><i class="fas fa-circle-question text-[11px] text-slate-300 hover:text-slate-500 cursor-help"></i>' +
      '<span class="invisible group-hover:visible absolute left-1/2 -translate-x-1/2 top-full mt-1 w-60 px-2 py-1.5 bg-slate-800 text-white text-[10px] rounded-md shadow-lg z-10 leading-relaxed normal-case font-normal">' + text + '</span></span>';
  }

  return '<div class="mb-5 flex items-start justify-between gap-4">' +
      '<div>' +
        '<h2 class="text-2xl font-black text-gray-900"><i class="fas fa-clipboard-check mr-2 text-blue-500"></i>Health Check Log</h2>' +
        '<p class="text-sm text-gray-500 mt-1">Platform monitor agent — run history, findings, and accumulated knowledge · refreshed ' + refreshedLabel + '</p>' +
      '</div>' +
      '<div class="flex-shrink-0">' + actionsHtml + '</div>' +
    '</div>' +
    bannerHtml +
    '<div class="space-y-6">' +
      saSection('Latest Successful Scan' + help('The hero card shows the most recent run that completed without errors. Trend sparkline plots health scores from successful runs in chronological order.'), 'fa-heart-pulse', heroHtml) +
      saSection('At a Glance' + help('Quick KPI overview. Runs are scheduled hourly via Cloudflare Cron — failures here usually mean the Anthropic API is unhealthy, not your platform.'), 'fa-tachometer-alt', kpisHtml) +
      saSection('Insights & Findings (' + insights.length + ')' + help('AI-generated suggestions from successful scans. Click Acknowledge to mark as seen, Resolve when fixed.'), 'fa-lightbulb', insightsHtml) +
      saSection('Recent Runs (' + runs.length + ')' + help('Last 30 monitor executions. Repeat errors at the top are collapsed into a single row to reduce noise.'), 'fa-history', runsHtml) +
      saSection('Accumulated Platform Knowledge' + help('A running summary Claude maintains about your platform. Each successful scan updates this memory so future scans can detect regressions.'), 'fa-brain', memoryHtml) +
    '</div>';
}

// ── Action handlers (Run now, Acknowledge, Resolve) ────────────
window.hclRunNow = async function() {
  var btn = document.getElementById('hcl-run-now-btn');
  if (btn) { btn.disabled = true; btn.innerHTML = '<i class="fas fa-spinner fa-spin text-[10px]"></i><span>Running…</span>'; }
  try {
    var res = await saFetch('/api/agent-hub/monitor/run', { method: 'POST' });
    if (!res || !res.ok) {
      var msg = 'Run failed';
      try { var j = await res.json(); msg = j.error || msg; } catch(e){}
      alert('Monitor scan: ' + msg);
    }
  } catch(e) {
    alert('Monitor scan failed: ' + (e && e.message || e));
  } finally {
    // Refresh the view either way — the new run row should now be at the top
    if (typeof loadView === 'function') loadView('platform-health-log');
  }
};

window.hclAckInsight = async function(id) {
  try {
    await saFetch('/api/agent-hub/monitor/insights/' + id + '/acknowledge', { method: 'POST' });
    if (typeof loadView === 'function') loadView('platform-health-log');
  } catch(e) { alert('Acknowledge failed: ' + (e && e.message || e)); }
};

window.hclResolveInsight = async function(id) {
  try {
    await saFetch('/api/agent-hub/monitor/insights/' + id + '/resolve', { method: 'POST' });
    if (typeof loadView === 'function') loadView('platform-health-log');
  } catch(e) { alert('Resolve failed: ' + (e && e.message || e)); }
};

// ============================================================
// UNIFIED CUSTOMERS DIRECTORY
// ============================================================

// ───────────────────────────────────────────────────────────────────────
// LIVE ACTIVITY — last 10 customer logins, time-spent, pages visited.
// Data source: GET /api/activity/customer-recent-logins.
// Auto-refreshes every 20s while the tab is active; saLiveActivityStop is
// called from saSwitchView so we never poll a hidden tab.
// ───────────────────────────────────────────────────────────────────────

function laTimeAgo(iso) {
  if (!iso) return '—';
  var t = Date.parse(iso.indexOf('Z') >= 0 || iso.indexOf('+') >= 0 ? iso : iso + 'Z');
  if (!isFinite(t)) return '—';
  var sec = Math.max(0, Math.floor((Date.now() - t) / 1000));
  if (sec < 60) return sec + 's ago';
  if (sec < 3600) return Math.floor(sec / 60) + ' min ago';
  if (sec < 86400) return Math.floor(sec / 3600) + 'h ' + (Math.floor((sec % 3600) / 60)) + 'm ago';
  return Math.floor(sec / 86400) + 'd ago';
}

function laFormatDuration(sec) {
  sec = Math.max(0, Math.round(sec || 0));
  if (sec < 60) return sec + 's';
  var m = Math.floor(sec / 60);
  var s = sec % 60;
  if (m < 60) return m + 'm ' + s + 's';
  var h = Math.floor(m / 60);
  return h + 'h ' + (m % 60) + 'm';
}

function laFormatPath(p) {
  if (!p) return '/';
  // Hide the heartbeat / API noise — we only show the page path. The path
  // sent by the heartbeat client IS the page path (window.location.pathname),
  // so this guard is mostly defensive.
  if (p.indexOf('/api/') === 0) return p;
  return p;
}

function escapeHTML(s) {
  return String(s == null ? '' : s)
    .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;').replace(/'/g, '&#39;');
}

function renderLiveActivityView() {
  var d = SA.data.liveActivity || { logins: [] };
  var logins = d.logins || [];
  var serverTime = d.server_time ? new Date(d.server_time).toLocaleTimeString() : '—';

  var header =
    '<div class="flex items-center justify-between mb-4">' +
      '<div>' +
        '<h2 class="text-xl font-bold text-white">Customer Live Activity</h2>' +
        '<p class="text-sm text-gray-400 mt-1">Last 10 customers to log in &mdash; with time spent and pages visited this session.</p>' +
      '</div>' +
      '<div class="flex items-center gap-3 text-xs text-gray-400">' +
        '<span class="inline-flex items-center gap-1.5"><span style="display:inline-block;width:8px;height:8px;border-radius:50%;background:#22c55e;animation:pulse 2s infinite"></span>Auto-refresh 20s</span>' +
        '<span>Server: ' + serverTime + '</span>' +
      '</div>' +
    '</div>';

  if (!logins.length) {
    return header +
      '<div class="bg-gray-800 rounded-lg p-8 text-center text-gray-400">' +
        '<i class="fas fa-user-clock text-4xl mb-3 text-gray-600"></i>' +
        '<p class="text-sm">No customer logins recorded yet. Once a customer signs in, they\'ll appear here within a few seconds.</p>' +
      '</div>';
  }

  var rows = logins.map(function(l) {
    var liveBadge = l.live
      ? '<span class="inline-flex items-center gap-1 text-xs font-bold text-emerald-400 bg-emerald-900/30 px-2 py-0.5 rounded-full"><span style="display:inline-block;width:6px;height:6px;border-radius:50%;background:#10b981;animation:pulse 1.5s infinite"></span>Live now</span>'
      : '<span class="text-xs text-gray-500">Last seen ' + laTimeAgo(l.login_at) + '</span>';

    var pages = (l.pages || []).slice(0, 12);
    var pagesHtml = pages.length
      ? pages.map(function(p) {
          return '<div class="flex items-center justify-between py-1 px-2 hover:bg-gray-700/40 rounded text-xs">' +
            '<span class="font-mono text-gray-300 truncate">' + escapeHTML(laFormatPath(p.path)) + '</span>' +
            '<span class="text-gray-500 ml-2 flex-shrink-0">' + laTimeAgo(p.at) + '</span>' +
          '</div>';
        }).join('')
      : '<div class="text-xs text-gray-500 italic px-2 py-1">No page navigation recorded yet for this session.</div>';

    var pageCountSuffix = (l.pages || []).length > 12 ? ' <span class="text-gray-500">(showing 12 of ' + l.pages.length + ')</span>' : '';

    return (
      '<div class="bg-gray-800 rounded-lg p-4 mb-3 border border-gray-700">' +
        '<div class="flex items-start justify-between gap-4 mb-3">' +
          '<div class="min-w-0 flex-1">' +
            '<div class="flex items-center gap-2 flex-wrap">' +
              '<h3 class="text-base font-bold text-white truncate">' + escapeHTML(l.name || '(unknown)') + '</h3>' +
              liveBadge +
            '</div>' +
            '<div class="text-xs text-gray-400 mt-1">' +
              escapeHTML(l.email || '') +
              (l.company ? ' &middot; ' + escapeHTML(l.company) : '') +
            '</div>' +
          '</div>' +
          '<div class="text-right flex-shrink-0">' +
            '<div class="text-xs text-gray-500">Logged in</div>' +
            '<div class="text-sm font-bold text-amber-400" title="' + escapeHTML(l.login_at || '') + '">' + laTimeAgo(l.login_at) + '</div>' +
            '<div class="text-xs text-gray-500 mt-1">Time on site</div>' +
            '<div class="text-sm font-bold text-emerald-400">' + laFormatDuration(l.time_spent_seconds) + '</div>' +
          '</div>' +
        '</div>' +
        '<div class="border-t border-gray-700 pt-2">' +
          '<div class="text-xs text-gray-400 font-semibold uppercase tracking-wide mb-1">Pages visited' + pageCountSuffix + '</div>' +
          '<div class="space-y-0.5">' + pagesHtml + '</div>' +
        '</div>' +
      '</div>'
    );
  }).join('');

  return header + rows;
}

window._saLiveActivityTimer = null;

function saLiveActivityStartPolling() {
  saLiveActivityStop();
  window._saLiveActivityTimer = setInterval(async function() {
    if (SA.view !== 'live-activity') { saLiveActivityStop(); return; }
    try {
      var res = await saFetch('/api/activity/customer-recent-logins');
      if (res && res.ok) {
        SA.data.liveActivity = await res.json();
        var root = document.getElementById('sa-root');
        if (root) root.innerHTML = renderSectionTabs() + renderLiveActivityView();
      }
    } catch (e) { /* swallow — next tick will retry */ }
  }, 20000);
}

function saLiveActivityStop() {
  if (window._saLiveActivityTimer) {
    clearInterval(window._saLiveActivityTimer);
    window._saLiveActivityTimer = null;
  }
}

function renderPeopleDirectoryView() {
  var d = SA.data.people || {};
  var rawPeople = d.people || [];
  var total = d.total || 0;

  // Dedupe on lowercased email — same person can appear as both platform_user and crm_customer.
  // Keep the entry with the most populated fields; tag the survivor with a count pill if collapsed.
  function fieldScore(p) {
    var keys = ['name','email','phone','company_name','company','owner_company'];
    var n = 0;
    for (var i = 0; i < keys.length; i++) if (p[keys[i]] && String(p[keys[i]]).trim()) n++;
    return n;
  }
  var byKey = {};
  rawPeople.forEach(function(p) {
    var key = (p.email && String(p.email).trim().toLowerCase()) || ('id:' + p.person_type + ':' + p.id);
    if (!byKey[key]) { byKey[key] = { primary: p, dupes: 0, types: {} }; }
    else {
      byKey[key].dupes += 1;
      if (fieldScore(p) > fieldScore(byKey[key].primary)) {
        byKey[key].primary = p;
      }
    }
    byKey[key].types[p.person_type] = true;
  });
  var people = Object.keys(byKey).map(function(k) {
    var entry = byKey[k];
    entry.primary._dupCount = entry.dupes;
    entry.primary._dupTypes = Object.keys(entry.types);
    return entry.primary;
  });

  var typeFilters = [
    { id: '', label: 'All', icon: 'fa-users' },
    { id: 'platform_user', label: 'Platform Users', icon: 'fa-user-check' },
    { id: 'crm_customer', label: 'CRM Customers', icon: 'fa-home' },
    { id: 'prospect', label: 'Prospects', icon: 'fa-phone-volume' }
  ];

  var filtersHtml = '<div class="flex items-center gap-2">';
  typeFilters.forEach(function(f) {
    var active = (SA.peopleType || '') === f.id;
    filtersHtml += '<button onclick="peopleFilterType(\'' + f.id + '\')" class="px-3 py-1.5 rounded-lg text-xs font-semibold transition-all ' +
      (active ? 'bg-slate-800 text-white shadow-sm' : 'bg-white text-gray-600 hover:bg-gray-100 border border-gray-200') + '">' +
      '<i class="fas ' + f.icon + ' mr-1"></i>' + f.label + '</button>';
  });
  filtersHtml += '</div>';

  var searchHtml = '<div class="relative">' +
    '<input type="text" id="people-search" placeholder="Search by name, email, phone, company..." value="' + (SA.peopleSearch || '') + '" ' +
    'onkeydown="if(event.key===\'Enter\')peopleDoSearch()" ' +
    'class="w-full pl-9 pr-4 py-2 text-sm border border-gray-200 rounded-lg focus:ring-2 focus:ring-slate-500 focus:border-slate-500">' +
    '<i class="fas fa-search absolute left-3 top-2.5 text-gray-400 text-sm"></i>' +
    '</div>';

  var typeBadge = { platform_user: 'bg-blue-100 text-blue-800', crm_customer: 'bg-green-100 text-green-800', prospect: 'bg-orange-100 text-orange-800' };
  var typeLabel = { platform_user: 'Platform User', crm_customer: 'CRM Customer', prospect: 'Prospect' };

  var listHtml = '';
  if (people.length === 0) {
    listHtml = '<div class="text-center py-16 text-gray-400"><i class="fas fa-users text-4xl mb-3"></i><p class="font-medium">No people found</p></div>';
  } else {
    listHtml = '<div class="overflow-x-auto"><table class="w-full text-sm"><thead><tr class="bg-gray-50 text-left"><th class="px-4 py-2 font-semibold text-gray-600">Name</th><th class="px-4 py-2 font-semibold text-gray-600">Email</th><th class="px-4 py-2 font-semibold text-gray-600">Phone</th><th class="px-4 py-2 font-semibold text-gray-600">Company</th><th class="px-4 py-2 font-semibold text-gray-600">Type</th><th class="px-4 py-2 font-semibold text-gray-600">Logins</th><th class="px-4 py-2 font-semibold text-gray-600">Last Login</th><th class="px-4 py-2 font-semibold text-gray-600">Joined</th></tr></thead><tbody>';
    people.forEach(function(p) {
      var badge = typeBadge[p.person_type] || 'bg-gray-100 text-gray-600';
      var label = typeLabel[p.person_type] || p.person_type;
      var dupPill = (p._dupCount > 0)
        ? ' <span title="' + (p._dupTypes || []).join(', ') + '" class="ml-1 px-1.5 py-0.5 bg-amber-100 text-amber-700 rounded text-[10px] font-bold">+' + p._dupCount + ' dup</span>'
        : '';
      var loginsCell = (p.person_type === 'platform_user')
        ? '<td class="px-4 py-3 text-xs text-gray-700 font-semibold">' + (p.login_count != null ? p.login_count : 0) + '</td>'
        : '<td class="px-4 py-3 text-gray-300 text-xs">—</td>';
      var lastLoginCell = (p.person_type === 'platform_user')
        ? (p.last_login
            ? '<td class="px-4 py-3 text-xs text-gray-600 whitespace-nowrap">' + fmtDateTime(p.last_login) + '</td>'
            : '<td class="px-4 py-3 text-xs"><span class="px-2 py-0.5 bg-red-50 text-red-600 rounded-full text-[10px] font-semibold uppercase">Never</span></td>')
        : '<td class="px-4 py-3 text-gray-300 text-xs">—</td>';
      listHtml += '<tr class="border-t border-gray-100 hover:bg-gray-50 cursor-pointer" onclick="peopleOpenProfile(\'' + p.person_type + '\',' + p.id + ')">' +
        '<td class="px-4 py-3 font-medium text-gray-900">' + (p.name || '—') + dupPill + '</td>' +
        '<td class="px-4 py-3 text-gray-500">' + (p.email || '—') + '</td>' +
        '<td class="px-4 py-3 text-gray-500">' + (p.phone || '—') + '</td>' +
        '<td class="px-4 py-3 text-gray-500">' + (p.company_name || p.company || p.owner_company || '—') + '</td>' +
        '<td class="px-4 py-3"><span class="px-2 py-0.5 ' + badge + ' rounded-full text-xs font-medium">' + label + '</span></td>' +
        loginsCell +
        lastLoginCell +
        '<td class="px-4 py-3 text-gray-400 text-xs">' + fmtDate(p.created_at) + '</td>' +
      '</tr>';
    });
    listHtml += '</tbody></table></div>';
  }

  return '<div class="mb-5"><h2 class="text-2xl font-black text-gray-900"><i class="fas fa-address-book mr-2 text-blue-500"></i>People Directory</h2><p class="text-sm text-gray-500 mt-1">Unified search across platform users, CRM customers, and prospects</p></div>' +
    '<div class="bg-white rounded-xl border border-gray-200 shadow-sm">' +
      '<div class="p-4 border-b border-gray-100 flex items-center justify-between gap-4 flex-wrap">' +
        filtersHtml +
        '<div class="w-72">' + searchHtml + '</div>' +
      '</div>' +
      listHtml +
      '<div class="p-3 border-t border-gray-100 text-xs text-gray-400 text-center">Showing ' + people.length + ' unique of ' + total + ' total records (deduped on email)</div>' +
    '</div>';
}

function peopleFilterType(type) {
  SA.peopleType = type;
  loadView('people-directory');
}

function peopleDoSearch() {
  var el = document.getElementById('people-search');
  SA.peopleSearch = el ? el.value : '';
  loadView('people-directory');
}

// Phase 4 #15: in-place slide-over for the People Directory. Works for all
// three person_types (platform_user / crm_customer / prospect) so admins can
// drill into a row without leaving the search/filter context.
async function peopleOpenProfile(type, id) {
  if (!type || !id) return;
  // Mount container — created lazily so it doesn't bloat the initial DOM.
  var host = document.getElementById('sa-person-panel-host');
  if (!host) {
    host = document.createElement('div');
    host.id = 'sa-person-panel-host';
    document.body.appendChild(host);
  }
  host.innerHTML =
    '<div id="sa-person-panel-overlay" class="fixed inset-0 bg-black/40 z-50" onclick="peopleClosePanel()"></div>' +
    '<aside id="sa-person-panel" class="fixed right-0 top-0 bottom-0 w-full max-w-md bg-white shadow-2xl z-50 overflow-y-auto transform transition-transform" style="transform:translateX(100%)">' +
      '<div class="p-6">' +
        '<div class="flex items-center justify-between mb-4">' +
          '<h3 class="text-base font-bold text-slate-700"><i class="fas fa-user mr-2 text-slate-400"></i>Customer Detail</h3>' +
          '<button onclick="peopleClosePanel()" class="w-8 h-8 flex items-center justify-center rounded-lg hover:bg-slate-100 text-slate-400" aria-label="Close"><i class="fas fa-times"></i></button>' +
        '</div>' +
        '<div id="sa-person-panel-body"><div class="py-12 text-center text-slate-400 text-sm"><i class="fas fa-circle-notch fa-spin mr-2"></i>Loading…</div></div>' +
      '</div>' +
    '</aside>';
  // Slide-in next tick so the transition runs.
  setTimeout(function() {
    var p = document.getElementById('sa-person-panel');
    if (p) p.style.transform = 'translateX(0)';
  }, 10);

  try {
    var res = await saFetch('/api/admin/superadmin/person/' + encodeURIComponent(type) + '/' + encodeURIComponent(id));
    var body = document.getElementById('sa-person-panel-body');
    if (!body) return;
    if (!res || !res.ok) {
      body.innerHTML = '<div class="py-8 text-center text-red-500 text-sm"><i class="fas fa-exclamation-circle mr-2"></i>Failed to load (' + (res ? res.status : 'network') + ')</div>';
      return;
    }
    var d = await res.json();
    body.innerHTML = renderPersonPanelBody(d);
  } catch (e) {
    var body2 = document.getElementById('sa-person-panel-body');
    if (body2) body2.innerHTML = '<div class="py-8 text-center text-red-500 text-sm"><i class="fas fa-exclamation-circle mr-2"></i>' + (e && e.message ? e.message : 'Error') + '</div>';
  }
}

function peopleClosePanel() {
  var p = document.getElementById('sa-person-panel');
  if (p) p.style.transform = 'translateX(100%)';
  setTimeout(function() {
    var host = document.getElementById('sa-person-panel-host');
    if (host) host.innerHTML = '';
  }, 250);
}

function renderPersonPanelBody(d) {
  function esc(s) { return String(s == null ? '' : s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }
  function row(label, value) {
    if (value == null || value === '') return '';
    return '<div class="flex items-start gap-3 py-2 border-b border-slate-50 last:border-0">' +
      '<div class="text-xs font-semibold text-slate-400 uppercase tracking-wide w-28 flex-shrink-0 pt-0.5">' + label + '</div>' +
      '<div class="text-sm text-slate-700 flex-1 break-words">' + value + '</div>' +
    '</div>';
  }
  var c = d.customer || {};
  var s = d.stats || {};
  var orders = d.recent_orders || [];
  var typeBadge = {
    platform_user: '<span class="px-2 py-0.5 bg-blue-100 text-blue-700 rounded-full text-[10px] font-bold uppercase tracking-wide">Platform User</span>',
    crm_customer: '<span class="px-2 py-0.5 bg-green-100 text-green-700 rounded-full text-[10px] font-bold uppercase tracking-wide">CRM Customer</span>',
    prospect: '<span class="px-2 py-0.5 bg-orange-100 text-orange-700 rounded-full text-[10px] font-bold uppercase tracking-wide">Prospect</span>'
  }[d.type] || '';
  var heading =
    '<div class="mb-5">' +
      '<div class="flex items-center gap-2 mb-1">' + typeBadge + (c.is_active === 0 ? '<span class="px-2 py-0.5 bg-red-100 text-red-700 rounded-full text-[10px] font-bold">SUSPENDED</span>' : '') + '</div>' +
      '<h2 class="text-xl font-bold text-slate-800">' + esc(c.name || c.email || ('#' + c.id)) + '</h2>' +
      (c.email ? '<a href="mailto:' + esc(c.email) + '" class="text-sm text-sky-600 hover:underline">' + esc(c.email) + '</a>' : '') +
    '</div>';
  var details =
    '<div class="bg-slate-50 rounded-xl p-4 mb-4">' +
      row('Phone', c.phone ? '<a href="tel:' + esc(c.phone) + '" class="text-sky-600 hover:underline">' + esc(c.phone) + '</a>' : '') +
      row('Company', esc(c.company_name || c.company || c.owner_company || '')) +
      row('Address', esc([c.address, c.city, c.province, c.postal_code].filter(Boolean).join(', '))) +
      row('Status', esc(c.status || '')) +
      row('Joined', c.created_at ? esc(fmtDate(c.created_at)) : '') +
      row('Last login', c.last_login ? esc(fmtDateTime(c.last_login)) : '') +
      row('Lead source', esc(c.lead_source || c.lead_utm_source || '')) +
      (c.owner_id ? row('Owned by', esc((c.owner_name || c.owner_email || '#' + c.owner_id) + (c.owner_company ? ' · ' + c.owner_company : ''))) : '') +
    '</div>';
  var statsHtml = '';
  if (d.type === 'platform_user') {
    statsHtml =
      '<div class="grid grid-cols-2 gap-2 mb-4">' +
        samc('Orders', s.order_count || 0, 'fa-clipboard-list', 'blue', (s.completed_orders || 0) + ' completed') +
        samc('Total paid', '$' + ((s.total_paid || 0)).toFixed(2), 'fa-dollar-sign', 'green', (s.invoice_count || 0) + ' invoices') +
        samc('Trial reports', (c.free_trial_used || 0) + '/' + (c.free_trial_total || 0), 'fa-gift', 'amber', (c.report_credits || 0) + ' credits') +
        samc('Secretary subs', s.active_secretary_subs || 0, 'fa-headset', (s.active_secretary_subs > 0 ? 'green' : 'gray'), s.last_order_at ? ('Last order ' + fmtDate(s.last_order_at)) : '') +
      '</div>';
    if (orders.length) {
      statsHtml += '<div class="bg-white border border-slate-100 rounded-xl p-3 mb-4">' +
        '<h4 class="text-xs font-bold uppercase tracking-wide text-slate-400 mb-2">Recent orders</h4>' +
        orders.map(function(o) {
          return '<div class="flex items-center justify-between py-1.5 border-b border-slate-50 last:border-0 text-xs">' +
            '<span class="font-mono text-slate-500">#' + esc(o.order_number || o.id) + '</span>' +
            '<span class="text-slate-700 truncate flex-1 mx-2">' + esc(o.property_address || '—') + '</span>' +
            '<span class="text-slate-400">' + (o.created_at ? esc(fmtDate(o.created_at)) : '') + '</span>' +
          '</div>';
        }).join('') +
      '</div>';
    }
  }
  return heading + details + statsHtml;
}
window.peopleClosePanel = peopleClosePanel;
window.peopleOpenProfile = peopleOpenProfile;

function renderPlatformSettingsView() {
  return '<div class="mb-5"><h2 class="text-2xl font-black text-gray-900"><i class="fas fa-cog mr-2 text-gray-500"></i>Platform Settings</h2><p class="text-sm text-gray-500 mt-1">Material preferences, SIP mapping, feature toggles</p></div>' +
    '<div class="grid grid-cols-1 md:grid-cols-3 gap-4">' +
      '<div onclick="saSetView(\'pricing\')" class="p-5 bg-white rounded-xl border border-gray-200 hover:shadow-md cursor-pointer transition-all"><i class="fas fa-tags text-2xl text-blue-500 mb-3"></i><h3 class="font-bold text-gray-900">Pricing & Tiers</h3><p class="text-xs text-gray-500 mt-1">Manage membership pricing and feature tiers</p></div>' +
      '<div onclick="saSetView(\'livekit-agents\')" class="p-5 bg-white rounded-xl border border-gray-200 hover:shadow-md cursor-pointer transition-all"><i class="fas fa-satellite text-2xl text-purple-500 mb-3"></i><h3 class="font-bold text-gray-900">LiveKit Agents</h3><p class="text-xs text-gray-500 mt-1">Agent deployment, phone pool, SIP trunks</p></div>' +
      '<div onclick="saSetView(\'telephony\')" class="p-5 bg-white rounded-xl border border-gray-200 hover:shadow-md cursor-pointer transition-all"><i class="fas fa-broadcast-tower text-2xl text-green-500 mb-3"></i><h3 class="font-bold text-gray-900">Telephony</h3><p class="text-xs text-gray-500 mt-1">SIP mapping, trunk status, voice config</p></div>' +
    '</div>';
}

// ============================================================
// USER ACTIVITY VIEW — time spent + module usage per user
// ============================================================
var UA_MODULE_LABELS = {
  measurement: 'Measurement',
  reports: 'Reports & Orders',
  crm: 'CRM / Pipeline',
  invoicing: 'Invoicing',
  proposals: 'Proposals',
  solar: 'Solar',
  secretary: 'AI Secretary',
  marketing: 'Marketing',
  team: 'Team',
  admin_tools: 'Admin Tools',
  customer_portal: 'Customer Portal',
  home_designer: 'Home Designer / AI',
  analytics_view: 'Analytics',
  other: 'Other'
};
var UA_MODULE_COLORS = {
  measurement: '#3b82f6', reports: '#10b981', crm: '#a855f7',
  invoicing: '#f59e0b', proposals: '#06b6d4', solar: '#eab308',
  secretary: '#ec4899', marketing: '#ef4444', team: '#14b8a6',
  admin_tools: '#64748b', customer_portal: '#0ea5e9',
  home_designer: '#8b5cf6', analytics_view: '#22c55e', other: '#94a3b8'
};

function uaFmtDuration(s) {
  s = Math.max(0, parseInt(s || 0, 10));
  if (s < 60) return s + 's';
  if (s < 3600) return Math.round(s / 60) + 'm';
  var h = Math.floor(s / 3600);
  var m = Math.round((s % 3600) / 60);
  return h + 'h' + (m ? ' ' + m + 'm' : '');
}

function uaModuleLabel(m) { return UA_MODULE_LABELS[m] || m; }

function uaSetPeriod(p) {
  SA.uaPeriod = p;
  loadView('user-activity');
}
function uaSetUserType(t) {
  SA.uaUserType = t;
  loadView('user-activity');
}

function renderUserActivityView() {
  var d = (SA.data && SA.data.userActivity) || {};
  var users = d.users || [];
  var modules = d.modules || [];
  var k = d.kpis || { active_users: 0, total_hours: 0, total_visits: 0, live_now: 0 };
  var period = SA.uaPeriod || '7d';
  var userType = SA.uaUserType || 'all';

  function pillBtn(value, current, label, onclick) {
    var active = value === current;
    return '<button onclick="' + onclick + '(\'' + value + '\')" class="px-3 py-1.5 rounded-lg text-xs font-semibold transition-all ' +
      (active ? 'bg-slate-800 text-white shadow-sm' : 'bg-gray-100 text-gray-600 hover:bg-gray-200') + '">' + label + '</button>';
  }

  var filterBar =
    '<div class="flex flex-wrap items-center gap-3 mb-5">' +
      '<div class="flex items-center gap-1">' +
        '<span class="text-[11px] font-bold text-gray-500 uppercase mr-2">Period</span>' +
        pillBtn('24h', period, '24h', 'uaSetPeriod') +
        pillBtn('7d', period, '7 days', 'uaSetPeriod') +
        pillBtn('30d', period, '30 days', 'uaSetPeriod') +
        pillBtn('90d', period, '90 days', 'uaSetPeriod') +
      '</div>' +
      '<div class="flex items-center gap-1 ml-4">' +
        '<span class="text-[11px] font-bold text-gray-500 uppercase mr-2">Type</span>' +
        pillBtn('all', userType, 'All', 'uaSetUserType') +
        pillBtn('admin', userType, 'Admin/Staff', 'uaSetUserType') +
        pillBtn('customer', userType, 'Customers', 'uaSetUserType') +
      '</div>' +
    '</div>';

  function kpi(label, value, icon, color) {
    return '<div class="bg-white rounded-xl p-4 border border-gray-200 shadow-sm">' +
      '<div class="flex items-center justify-between mb-2">' +
        '<span class="text-[10px] font-bold uppercase tracking-wider text-gray-500">' + label + '</span>' +
        '<i class="fas ' + icon + ' text-' + color + '-500"></i>' +
      '</div>' +
      '<div class="text-2xl font-black text-gray-900">' + value + '</div>' +
    '</div>';
  }

  var kpiRow =
    '<div class="grid grid-cols-2 md:grid-cols-4 gap-4 mb-6">' +
      kpi('Active Users', k.active_users, 'fa-users', 'blue') +
      kpi('Total Hours', k.total_hours + 'h', 'fa-clock', 'emerald') +
      kpi('Total Visits', k.total_visits, 'fa-mouse-pointer', 'purple') +
      kpi('Live Now', k.live_now, 'fa-circle', k.live_now > 0 ? 'green' : 'gray') +
    '</div>';

  // Top users table
  var rows = '';
  if (!users.length) {
    rows = '<tr><td colspan="7" class="px-4 py-12 text-center text-gray-400 text-sm">No activity recorded yet for this filter. Heartbeats begin after users navigate the app.</td></tr>';
  } else {
    users.forEach(function (u) {
      var typeBadge = u.user_type === 'admin'
        ? '<span class="px-2 py-0.5 rounded text-[10px] font-bold bg-red-100 text-red-700">ADMIN</span>'
        : '<span class="px-2 py-0.5 rounded text-[10px] font-bold bg-blue-100 text-blue-700">CUSTOMER</span>';
      var lastSeen = u.last_seen ? new Date(u.last_seen + 'Z').toLocaleString() : '—';
      var topModColor = UA_MODULE_COLORS[u.top_module] || '#94a3b8';
      var topModLabel = uaModuleLabel(u.top_module);
      rows +=
        '<tr class="border-b border-gray-100 hover:bg-gray-50 cursor-pointer" onclick="uaOpenDrillIn(\'' + u.user_type + '\',' + u.user_id + ')">' +
          '<td class="px-4 py-3"><div class="font-semibold text-gray-900 text-sm">' + (u.name || '—') + '</div><div class="text-[11px] text-gray-500">' + (u.email || '') + '</div></td>' +
          '<td class="px-4 py-3">' + typeBadge + '</td>' +
          '<td class="px-4 py-3 text-sm font-bold text-gray-900">' + uaFmtDuration(u.total_seconds) + '</td>' +
          '<td class="px-4 py-3 text-sm text-gray-700">' + (u.visit_count || 0) + '</td>' +
          '<td class="px-4 py-3"><span class="inline-flex items-center gap-1.5 text-xs font-medium"><span class="w-2 h-2 rounded-full" style="background:' + topModColor + '"></span>' + topModLabel + '</span></td>' +
          '<td class="px-4 py-3 text-[11px] text-gray-500">' + lastSeen + '</td>' +
          '<td class="px-4 py-3 text-right"><i class="fas fa-chevron-right text-gray-400 text-xs"></i></td>' +
        '</tr>';
    });
  }

  var tableHTML =
    '<div class="bg-white rounded-xl border border-gray-200 overflow-hidden mb-6">' +
      '<div class="px-5 py-3 border-b border-gray-200 flex items-center justify-between">' +
        '<h3 class="font-bold text-gray-900 text-sm"><i class="fas fa-trophy text-yellow-500 mr-1.5"></i>Top Users by Time Spent</h3>' +
        '<span class="text-[11px] text-gray-500">Top ' + users.length + ' · click row to drill in</span>' +
      '</div>' +
      '<div class="overflow-x-auto">' +
        '<table class="w-full text-left">' +
          '<thead class="bg-gray-50 border-b border-gray-200"><tr>' +
            '<th class="px-4 py-2 text-[10px] font-bold uppercase text-gray-500 tracking-wider">User</th>' +
            '<th class="px-4 py-2 text-[10px] font-bold uppercase text-gray-500 tracking-wider">Type</th>' +
            '<th class="px-4 py-2 text-[10px] font-bold uppercase text-gray-500 tracking-wider">Total Time</th>' +
            '<th class="px-4 py-2 text-[10px] font-bold uppercase text-gray-500 tracking-wider">Visits</th>' +
            '<th class="px-4 py-2 text-[10px] font-bold uppercase text-gray-500 tracking-wider">Top Module</th>' +
            '<th class="px-4 py-2 text-[10px] font-bold uppercase text-gray-500 tracking-wider">Last Seen</th>' +
            '<th></th>' +
          '</tr></thead>' +
          '<tbody>' + rows + '</tbody>' +
        '</table>' +
      '</div>' +
    '</div>';

  // Module breakdown bar chart
  var maxModSec = modules.reduce(function (a, m) { return Math.max(a, m.seconds || 0); }, 0) || 1;
  var modBars = modules.length
    ? modules.map(function (m) {
        var pct = Math.max(2, Math.round(((m.seconds || 0) / maxModSec) * 100));
        var color = UA_MODULE_COLORS[m.module] || '#94a3b8';
        return '<div class="mb-2.5">' +
          '<div class="flex items-center justify-between text-xs mb-1"><span class="font-medium text-gray-700">' + uaModuleLabel(m.module) + '</span><span class="text-gray-500">' + uaFmtDuration(m.seconds) + ' · ' + (m.visits || 0) + ' visits</span></div>' +
          '<div class="bg-gray-100 rounded-full h-2 overflow-hidden"><div class="h-full rounded-full" style="width:' + pct + '%; background:' + color + '"></div></div>' +
        '</div>';
      }).join('')
    : '<p class="text-gray-400 text-sm">No module data yet for this filter.</p>';

  var modSection =
    '<div class="bg-white rounded-xl border border-gray-200 p-5">' +
      '<h3 class="font-bold text-gray-900 text-sm mb-4"><i class="fas fa-th-large text-indigo-500 mr-1.5"></i>Module Usage Breakdown</h3>' +
      modBars +
    '</div>';

  return '<div class="mb-5">' +
      '<h2 class="text-2xl font-black text-gray-900"><i class="fas fa-user-clock mr-2 text-indigo-500"></i>User Activity</h2>' +
      '<p class="text-sm text-gray-500 mt-1">Time spent and module usage across admin/staff and customer-portal users. Heartbeats every 60s while a tab is visible.</p>' +
    '</div>' +
    filterBar + kpiRow + tableHTML + modSection +
    '<div id="ua-drill-in"></div>';
}

async function uaOpenDrillIn(userType, userId) {
  var panel = document.getElementById('ua-drill-in');
  if (!panel) return;
  panel.innerHTML = '<div class="bg-white rounded-xl border border-gray-200 p-6 mt-6 text-center text-gray-500 text-sm"><div class="inline-block w-6 h-6 border-2 border-indigo-500 border-t-transparent rounded-full animate-spin mr-2"></div>Loading user details…</div>';
  try {
    var res = await saFetch('/api/activity/user/' + userType + '/' + userId + '?period=' + (SA.uaPeriod || '7d'));
    if (!res || !res.ok) {
      panel.innerHTML = '<div class="bg-red-50 border border-red-200 text-red-700 rounded-xl p-5 mt-6 text-sm">Failed to load user details.</div>';
      return;
    }
    var data = await res.json();
    var profile = data.profile || {};
    var modules = data.modules || [];
    var daily = data.daily || [];
    var recent = data.recent || [];
    var maxModSec = modules.reduce(function (a, m) { return Math.max(a, m.seconds || 0); }, 0) || 1;
    var modList = modules.map(function (m) {
      var pct = Math.round(((m.seconds || 0) / maxModSec) * 100);
      var color = UA_MODULE_COLORS[m.module] || '#94a3b8';
      return '<div class="mb-2"><div class="flex justify-between text-xs mb-0.5"><span class="font-medium">' + uaModuleLabel(m.module) + '</span><span class="text-gray-500">' + uaFmtDuration(m.seconds) + '</span></div>' +
        '<div class="bg-gray-100 h-1.5 rounded-full"><div class="h-full rounded-full" style="width:' + pct + '%; background:' + color + '"></div></div></div>';
    }).join('') || '<p class="text-gray-400 text-sm">No data.</p>';

    var maxDaily = daily.reduce(function (a, m) { return Math.max(a, m.seconds || 0); }, 0) || 1;
    var dailyBars = daily.length
      ? '<div class="flex items-end gap-1 h-24 mb-1">' + daily.map(function (d) {
          var h = Math.max(2, Math.round(((d.seconds || 0) / maxDaily) * 92));
          return '<div class="flex-1 bg-indigo-500 rounded-t" style="height:' + h + 'px" title="' + d.day + ': ' + uaFmtDuration(d.seconds) + '"></div>';
        }).join('') + '</div>'
        + '<div class="flex justify-between text-[9px] text-gray-400">' +
            '<span>' + (daily[0] && daily[0].day || '') + '</span>' +
            '<span>' + (daily[daily.length - 1] && daily[daily.length - 1].day || '') + '</span>' +
          '</div>'
      : '<p class="text-gray-400 text-sm">No daily data.</p>';

    var recentRows = recent.map(function (r) {
      var color = UA_MODULE_COLORS[r.module] || '#94a3b8';
      return '<tr class="border-b border-gray-100"><td class="py-2 pr-3"><span class="inline-block w-2 h-2 rounded-full mr-2 align-middle" style="background:' + color + '"></span>' + uaModuleLabel(r.module) + '</td>' +
        '<td class="py-2 pr-3 text-gray-500 text-[11px]">' + (r.started_at || '') + '</td>' +
        '<td class="py-2 text-right font-semibold">' + uaFmtDuration(r.duration_seconds) + '</td></tr>';
    }).join('') || '<tr><td colspan="3" class="py-3 text-center text-gray-400">No visits yet.</td></tr>';

    var typeBadge = userType === 'admin'
      ? '<span class="px-2 py-0.5 rounded text-[10px] font-bold bg-red-100 text-red-700">ADMIN</span>'
      : '<span class="px-2 py-0.5 rounded text-[10px] font-bold bg-blue-100 text-blue-700">CUSTOMER</span>';

    panel.innerHTML =
      '<div class="bg-white rounded-xl border border-gray-200 p-5 mt-6">' +
        '<div class="flex items-start justify-between mb-4">' +
          '<div>' +
            '<h3 class="font-bold text-gray-900 text-base">' + (profile.name || 'Unknown') + ' ' + typeBadge + '</h3>' +
            '<p class="text-xs text-gray-500">' + (profile.email || '') + (profile.company_name ? ' · ' + profile.company_name : '') + '</p>' +
          '</div>' +
          '<button onclick="document.getElementById(\'ua-drill-in\').innerHTML=\'\'" class="text-gray-400 hover:text-gray-700 text-sm"><i class="fas fa-times"></i></button>' +
        '</div>' +
        '<div class="grid grid-cols-1 md:grid-cols-3 gap-4">' +
          '<div><h4 class="text-[10px] uppercase font-bold text-gray-500 tracking-wider mb-2">Daily Time (' + (SA.uaPeriod || '7d') + ')</h4>' + dailyBars + '</div>' +
          '<div><h4 class="text-[10px] uppercase font-bold text-gray-500 tracking-wider mb-2">Modules</h4>' + modList + '</div>' +
          '<div><h4 class="text-[10px] uppercase font-bold text-gray-500 tracking-wider mb-2">Recent Visits</h4><table class="w-full text-xs">' + recentRows + '</table></div>' +
        '</div>' +
      '</div>';

    // Scroll the drill-in into view.
    panel.scrollIntoView({ behavior: 'smooth', block: 'start' });
  } catch (e) {
    panel.innerHTML = '<div class="bg-red-50 border border-red-200 text-red-700 rounded-xl p-5 mt-6 text-sm">' + (e.message || 'Error loading details') + '</div>';
  }
}
